    """Resolve dict-based dynamic defaults now that every parameter
    has been parsed and :attr:`Context.params` is fully populated.

    An :class:`Option` may specify ``default`` as a mapping of
    ``{other_option_decl: {value: default}}``. Once all values are
    known, look up the referenced options' current values and use
    them to pick this option's default, but only if this option's
    value wasn't otherwise provided.

    .. versionadded:: 8.3
    """
    params = self.get_params(ctx)

    def _find_param(opt: str) -> Parameter | None:
        for candidate in params:
            if opt in candidate.opts or opt in candidate.secondary_opts:
                return candidate

        return None

    for param in params:
        if not isinstance(param, Option) or param._dynamic_default is None:
            continue

        if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:  # type: ignore[arg-type]
            continue

        resolved = None

